#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    // Use pointers for fast access to contiguous storage
    double* Cbuf = nullptr;
    double* Abuf = nullptr;
    std::vector<double*> Cp(n), Ap(n);

    for (int i = 0; i < n; ++i) {
        Cp[i] = C[i].data();
        Ap[i] = A[i].data();
    }

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* c_row = Cp[i];
        const double* a_row = Ap[i];

        // First scale the lower part of the i-th row by beta
        for (int j = 0; j <= i; ++j)
            c_row[j] *= beta;

        // Accumulate alpha * A[i][k] * A[j][k]
        for (int k = 0; k < m; ++k) {
            double aik = a_row[k];
            for (int j = 0; j <= i; ++j)
                c_row[j] += alpha * aik * Ap[j][k];
        }
    }
}
