#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
		     std::vector<std::vector<double>>& A) {
#pragma omp parallel for schedule(static) shared(A) shared(n)
    for (int i = 0; i < n; ++i) {
        /* pointer to the i‑th row for faster indexing */
        double* Ai = A[i].data();

        /* off‑diagonal elements */
        for (int j = 0; j < i; ++j) {
            double* Aj = A[j].data();
            double s = 0.0;
            for (int k = 0; k < j; ++k)
                s += Ai[k] * Aj[k];
            Ai[j] = (Ai[j] - s) / Aj[j];
        }

        /* diagonal element */
        double s = 0.0;
        for (int k = 0; k < i; ++k)
            s += Ai[k] * Ai[k];
        Ai[i] = std::sqrt(Ai[i] - s);
    }
}
