void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Flatten the 2‑D path into a 1‑D array to avoid virtual index lookup
    std::vector<int32_t> flat(n * n);
    for (int i = 0; i < n; ++i)
        std::copy(path[i].begin(), path[i].end(), flat.begin() + i * n);

    // Main algorithm – parallelise over i and j
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < n; ++k) {
        const int32_t* base_k = flat.data() + k * n;   // row k
        for (int i = 0; i < n; ++i) {
            int32_t* row_i = flat.data() + i * n;     // row i
            int32_t aik = row_i[k];
            for (int j = 0; j < n; ++j) {
                int32_t new_path = aik + base_k[j];
                if (new_path < row_i[j]) row_i[j] = new_path;
            }
        }
    }

    // Dump back to the original 2‑D vector
    for (int i = 0; i < n; ++i)
        std::copy(flat.begin() + i * n, flat.begin() + (i + 1) * n,
                  path[i].begin());
}
