/* Forward substitution routine – identical behaviour to the original */
// pragma: no parallelisation as each iteration depends on the ones before
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    double *xdata = x.data();
    double *bdata = b.data();

    for (int i = 0; i < n; ++i) {
        double sum = bdata[i];
        double *Lrow = L[i].data();

#pragma GCC ivdep   // tells the compiler the inner loop is free of dependence
        for (int j = 0; j < i; ++j) {
            sum -= Lrow[j] * xdata[j];
        }
        xdata[i] = sum / Lrow[i];
    }
