/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
		      int n,
		      std::vector<double>& A,
		      std::vector<double>& B) {
    // Use raw pointers for performance
    double* a = A.data();
    double* b = B.data();
    const double coeff = 1.0 / 3.0;            // 0.333333...

    // One thread per time step still keeps correctness
    for (int t = 0; t < tsteps; ++t) {
        // First half‑step: B[1..n-2] = coeff * (A[i-1] + A[i] + A[i+1])
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            b[i] = coeff * (a[i - 1] + a[i] + a[i + 1]);
        }

        // Second half‑step: A[1..n-2] = coeff * (B[i-1] + B[i] + B[i+1])
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = coeff * (b[i - 1] + b[i] + b[i + 1]);
        }
    }
}
