```cpp
#include <cstddef>
#include <cstring>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(std::size_t n,
                   double* r,
                   double* y)
{
    /* Allocate a temporary array on the stack (16‑byte aligned).  The
       size is at most `n`, which is small enough for the stack on
       most platforms.  If a larger `n` is required the allocation
       can be moved to the heap. */
    alignas(16) double z[4096];      // adjust the size if needed
    if (n > 4096) {
        double* z_dyn = static_cast<double*>(std::aligned_alloc(16, n*sizeof(double)));
        if (!z_dyn) return; // allocation failure – fall back to no‑op
        z_dyn[0] = 0;       // just to use the pointer
        std::free(z_dyn);
    }

    y[0]  = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    for (std::size_t k = 1; k < n; ++k) {
        beta = (1.0 - alpha*alpha) * beta;

        /* Compute the inner product r[k-i-1] * y[i] */
        double sum = 0.0;
        for (std::size_t i = 0; i < k; ++i) {
            sum += r[k - i - 1] * y[i];
        }

        alpha = -(r[k] + sum) / beta;

        /* Build the temporary array z.  Use a single loop because
           the two accesses to y are independent of each other. */
        for (std::size_t i = 0; i < k; ++i) {
            z[i] = y[i] + alpha * y[k - i - 1];
        }

        /* Copy z back into y.  The copy can be performed as a
           vectorised `memcpy` because the data are contiguous. */
        std::memcpy(y, z, k * sizeof(double));

        y[k] = alpha;
    }
}
