#include <omp.h>        // OpenMP

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y) {

    // Flatten access to the input matrices for maximum spatial locality.
    const double *Adata = &A[0][0];
    const double *Bdata = &B[0][0];
    const double *xdata = &x[0];
    double *tmpdata = &tmp[0];
    double *yd   = &y[0];

    const int stride = n;                     // Row stride
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double *Arow = Adata + i * stride;
        const double *Brow = Bdata + i * stride;
        double tmp_val = 0.0;
        double y_val   = 0.0;

        for (int j = 0; j < n; ++j) {
            const double xj = xdata[j];
            tmp_val += Arow[j] * xj;
            y_val   += Brow[j] * xj;
        }

        tmpdata[i] = tmp_val;
        yd[i]      = alpha * tmp_val + beta * y_val;
    }
}
```
