#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        const double *aptr = A[i].data();          /* A[i][*] row */
        const double *yptr = py1;                   /* y1[j] */
        for (int j = 0; j < n; ++j, ++aptr, ++yptr) {
            sum += (*aptr) * (*yptr);
