#include <vector>
#include <omp.h>
#include <cstddef>
#include <algorithm>

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    const double n_inv = 1.0 / static_cast<double>(n);
    const double n1_inv = 1.0 / static_cast<double>(n - 1);

    // zero the mean vector
    std::fill(mean.begin(), mean.end(), 0.0);

    /*======================================================================
     * 1. Compute means  (parallel over columns j)
     *======================================================================
     */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum * n_inv;
    }

    /*======================================================================
     * 2. Center the data (parallel over rows i)
     *======================================================================
     */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();
        const double* mu  = mean.data();
        for (int j = 0; j < m; ++j) {
            row[j] -= mu[j];
        }
    }

    /*======================================================================
     * 3. Compute covariance matrix (parallel over upper triangle)
     *======================================================================
     */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double acc = 0.0;
            for (int k = 0; k < n; ++k) {
                acc += data[k][i] * data[k][j];
            }
            double value = acc * n1_inv;
            cov[i][j] = value;
            if (j != i) {
                cov[j][i] = value;
            }
        }
    }
}
