#include <cmath>
#include <vector>
#include <omp.h>

/* QR Decomposition with Modified Gram Schmidt.
 * The vectors of vectors are flattened into column‑major order for
 * maximum spatial locality. All arrays are passed by reference so that
 * the harness can re‑use the same memory.
 */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    // Flatten the 2‑D vectors into 1‑D arrays in column‑major order
    std::vector<double> aval(m * n), rval(n * n), qval(m * n);

    #pragma omp parallel for collapse(2)
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            aval[i + j * m] = A[i][j];

    for (int k = 0; k < n; ++k) {
        // ----------- compute norm of column k -------------------------
        double nrm = 0.0;
        for (int i = 0; i < m; ++i)
            nrm += aval[i + k * m] * aval[i + k * m];
        rval[k + k * n] = std::sqrt(nrm);
        double rk = rval[k + k * n];

        // ----------- normalize column to form Q -----------------------
        for (int i = 0; i < m; ++i)
            qval[i + k * m] = aval[i + k * m] / rk;

        // ----------- orthogonalize remaining columns ------------------
        for (int j = k + 1; j < n; ++j) {
            double dot = 0.0;
            for (int i = 0; i < m; ++i)
                dot += qval[i + k * m] * aval[i + j * m];
            rval[k + j * n] = dot;

            for (int i = 0; i < m; ++i)
                aval[i + j * m] -= qval[i + k * m] * dot;
        }
    }

    // Store back into the provided 2‑D vectors
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j) {
            A[i][j] = aval[i + j * m];
            R[i][j] = rval[i + j * n];
            Q[i][j] = qval[i + j * m];
        }
}
