void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B)
{
    const double w = 0.2;              // constant multiplier

    // Pointers to the row data to avoid repeated bound checking
    std::vector<double*> a(n), b(n);
    for (int i = 0; i < n; ++i) {
        a[i] = A[i].data();
        b[i] = B[i].data();
    }

    // Main time‑stepping loop
    for (int t = 0; t < tsteps; ++t) {
        // First half: update B from A
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            double* aip1   = a[i+1];
            double* ai     = a[i];
            double* aipm1  = a[i-1];
            double* bip1   = b[i+1];
            double* bi     = b[i];
            double* bipm1  = b[i-1];

            for (int j = 1; j < n - 1; ++j) {
                bi[j] = w * (ai[j] + ai[j-1] + ai[j+1] + aip1[j] + aipm1[j]);
            }
        }

        // Second half: update A from B
