#include <vector>
#include <cstddef>
#include <omp.h>

/* Copy the input matrix into a contiguous block of memory. This
   layout matches the access pattern of the algorithm and allows
   efficient vectorisation. The function works with the same
   signature that the harness expects. */
static inline void copy_to_contiguous(const std::vector<std::vector<double>>& src,
                                      double* dst,
                                      std::size_t n)
{
    for (std::size_t i = 0; i < n; ++i)
        std::memcpy(dst + i * n, src[i].data(), n * sizeof(double));
}

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_lu(int n,
               std::vector<std::vector<double>>& A)
{
    /* Work on a contiguous copy to avoid indirect addressing and
       to enable better vectorisation. */
    std::vector<double> contiguous(n * n);
    copy_to_contiguous(A, contiguous.data(), n);

    /* The algorithm is inherently sequential in the outer loop (i),
       because each row depends on all previous rows.  However, the
       inner loops for row‑i can be parallelised.  OpenMP is used
       only for the two inner loops that are independent of each
       other, not for the outer i‑loop. */
    #pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < n; ++i) {
        double* row_i = contiguous.data() + i * n;

        /* Update U[i][j] for j = 0 … i-1 (lower part) */
        for (int j = 0; j < i; ++j) {
            double sum = row_i[j];
            double* row_k = contiguous.data() + i * n;

            for (int k = 0; k < j; ++k)
                sum -= row_k[k] * contiguous[k * n + j];

            row_i[j] = sum / contiguous[j * n + j];
        }

        /* Update U[i][j] for j = i … n-1 (upper part) */
        for (int j = i; j < n; ++j) {
            double sum = row_i[j];
            for (int k = 0; k < i; ++k)
                sum -= row_i[k] * contiguous[k * n + j];
            row_i[j] = sum;
        }
    }

    /* Copy the result back to the original vector of vectors. */
    for (int i = 0; i < n; ++i)
        std::memcpy(A[i].data(), contiguous.data() + i * n, n * sizeof(double));
}
