```cpp
#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    // Constant alpha * beta to avoid repeated multiplication
    const double alpha_beta = alpha;

    // Use a block size that fits comfortably in L2 cache
    constexpr std::size_t BLOCK = 16;   /* tweak if needed */

    // Parallelize over the outermost loop (rows of C)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        /* 1st phase – multiply the existing lower‑triangular part of C by beta */
        for (int j = 0; j <= i; ++j) {
            C[i][j] *= beta;
        }

        /* 2nd phase – accumulate rank‑m updates from A and B */
        for (int kk = 0; kk < m; kk += BLOCK) {
            const int kmax = std::min(kk + BLOCK, m);

            /* Inner k‑loop is blocked */
            for (int k = kk; k < kmax; ++k) {
                const double aik = A[i][k] * alpha_beta;   // A[i][k]*alpha
                const double bk  = B[i][k];                // B[i][k]
                const double bk_alpha = bk * alpha_beta;   // alpha*B[i][k]

                /* Update the lower triangle of row i */
                for (int j = 0; j <= i; ++j) {
                    C[i][j] += A[j][k] * bk_alpha + B[j][k] * aik;
                }
            }
        }
    }
}
```

This implementation keeps the exact functional semantics while:

* Using **OpenMP** to parallelize work across rows of `C`.
* Working with a small cache‑friendly **blocking** of the `k` dimension.
* Reducing the number of floating‑point multiplications by pre‑multiplying constants (`alpha`).
* Maintaining lower‑triangular storage semantics and in‑place updates.

