/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum)
{
    /* Parallelise over the outermost loop (r).  The inner work is
       small enough that a static schedule with chunk size 1 gives
       the best balance. */
#pragma omp parallel for schedule(static,1)
    for (int r = 0; r < nr; ++r) {
        /* Local pointers to the r‑th layer of A for quicker access. */
        const auto* Ar = A[r].data();
        double*   Ar_out = A[r].data();

        for (int q = 0; q < nq; ++q) {
            /* Pointer to the q‑th slice for current r. */
            const double* A_rq = Ar[q].data();
            double*       A_rq_out = Ar_out[q].data();

            /* Pointer to the q‑th column of C4 (sindex fixed by column). */
            const double* C4_col = C4.data() + 0; // will be indexed below

            for (int p = 0; p < np; ++p)
                sum[p] = 0.0;

            /* Perform the inner product. */
            for (int s = 0; s < np; ++s) {
                const double a = A_rq[s];
                const double* C4_s = C4[s].data();
                for (int p = 0; p < np; ++p)
                    sum[p] += a * C4_s[p];
            }

            /* Copy the result back to A. */
            std::memcpy(A_rq_out, sum.data(), np * sizeof(double));
        }
    }
}
```

