                 std::vector<std::vector<double>>& B)
{
    /* The update of B[i][j] depends only on rows k > i.
       Hence rows can be processed independently and in parallel. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        /* Pointers to the i‑th row of B and all rows of A
           for fast indexed access. */
        double* B_row = B[i].data();

        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            for (int k = i + 1; k < m; ++k) {
                /* A[k][i] is a column element of A; although
                   A is stored row‑wise, this direct access
                   is still the most efficient way under the
                   given interface. */
                sum += A[k][i] * B[k][j];
            }
            B_row[j] = alpha * (B_row[j] + sum);
        }
    }
}
