void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    // initialise y – can be done in parallel
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) y[i] = 0.0;

    // compute tmp = A * x   and   y   = Aᵀ * tmp   in one pass
    // each thread keeps its own partial y to avoid atomic updates
    const int num_threads = omp_get_max_threads();
    std::vector<std::vector<double>> y_local(num_threads, std::vector<double>(n, 0.0));

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::vector<double> &y_buf = y_local[tid];

        #pragma omp for schedule(static)
        for (int i = 0; i < m; ++i) {
            // compute tmp[i]
            double sum = 0.0;
            const std::vector<double>* Ai = &A[i];
            for (int j = 0; j < n; ++j) sum += (*Ai)[j] * x[j];
            tmp[i] = sum;

            // accumulate into local y buffer
            for (int j = 0; j < n; ++j) {
                y_buf[j] += (*Ai)[j] * sum;
            }
        }
    }

    // merge local y buffers
    for (int t = 0; t < num_threads; ++t) {
        for (int j = 0; j < n; ++j) y[j] += y_local[t][j];
    }
}
