void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // Parallelise the outer loop over rows of C (and A).
    // The work per iteration is independent.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i)
    {
        double* crow = &C[i][0];          // pointer to C's i-th row
        const double* arow = &A[i][0];    // pointer to A's i-th row

        // Scale the output row by beta once.
        for (int j = 0; j < nj; ++j)
            crow[j] *= beta;

        // Standard row‑wise accumulate A[i][k] * B[k][j].
        for (int k = 0; k < nk; ++k)
        {
            double aik = arow[k] * alpha;              // pre‑multiply alpha * A[i][k]
            const double* brow = &B[k][0];             // pointer to B's k-th row
            // Unroll the inner j loop by 4 for a little extra speed.
            int j = 0;
            for (; j <= nj - 4; j += 4)
            {
                crow[j]     += aik * brow[j];
                crow[j + 1] += aik * brow[j + 1];
                crow[j + 2] += aik * brow[j + 2];
                crow[j + 3] += aik * brow[j + 3];
            }
            for (; j < nj; ++j)
                crow[j] += aik * brow[j];
        }
    }
}
