            int k = 0;
            for (; k <= nk - 4; k += 4) {
                b_col = B[k].data();
                sum += alpha * a_row[k] * b_col[j];
                sum += alpha * a_row[k+1] * B[k+1][j];
                sum += alpha * a_row[k+2] * B[k+2][j];
