#include <vector>
#include <algorithm>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return.
   Optimised version for modern x86‑64 (gcc –O2 –fopenmp).
*/
void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    // Flatten the 2‑D table to a 1‑D array for contiguous access.
    // 'table' is assumed to be sized n×n beforehand.
    std::vector<int> tbl(n * n);
    for (int i = 0; i < n; ++i)
        std::copy(table[i].begin(), table[i].end(), tbl.begin() + i * n);

    // Helper to index the flat array
    auto idx = [n](int i, int j) -> int { return i * n + j; };

    // OpenMP parallelise over the outer dimension (i).  
    // The dependence chain goes from higher i to lower i, so we
    // iterate i from n−1 downto 0 in parallel (schedule dynamic for load balance).
#pragma omp parallel for schedule(dynamic, 16) // chunk size tuned experimentally
    for (int i = n - 1; i >= 0; --i) {
        for (int j = i + 1; j < n; ++j) {
            // Local copy of current cell value
            int best = tbl[idx(i, j)];

            // Corresponds to: table[i][j] = max(table[i][j], table[i][j-1]);
            if (j - 1 >= 0) {
                best = std::max(best, tbl[idx(i, j - 1)]);
            }

            // Corresponds to: table[i][j] = max(table[i][j], table[i+1][j]);
            if (i + 1 < n) {
                best = std::max(best, tbl[idx(i + 1, j)]);
            }

            // Corresponds to the match/loop case
            if (j - 1 >= 0 && i + 1 < n) {
                if (i < j - 1) {
                    int match = (seq[i] + seq[j] == 3) ? 1 : 0;
                    best = std::max(best, tbl[idx(i + 1, j - 1)] + match);
                } else { // i == j-1
                    best = std::max(best, tbl[idx(i + 1, j - 1)]);
                }
            }

            // Partitioning step
            for (int k = i + 1; k < j; ++k) {
                int val = tbl[idx(i, k)] + tbl[idx(k + 1, j)];
                if (val > best) best = val;
            }

            tbl[idx(i, j)] = best;
        }
    }

    // Copy back to the original vector of vectors
    for (int i = 0; i < n; ++i)
        std::copy(tbl.begin() + i * n, tbl.begin() + (i + 1) * n,
                  table[i].begin());
}
