#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    // Work in a contiguous storage view for faster pointer arithmetic
    const size_t N = static_cast<size_t>(n);
    std::vector<double> flatA(N * N);
    for (size_t i = 0; i < N; ++i)
        std::copy(A[i].begin(), A[i].end(), flatA.begin() + i * N);

    /* --- LU Decomposition ------------------------------------------------ */
    for (int i = 0; i < n; ++i) {
        size_t ii = static_cast<size_t>(i);
        // Solve for lower part (j < i)
        for (int j = 0; j < i; ++j) {
            double w = flatA[ii * N + j];
#pragma omp parallel for schedule(static)
            for (int k = 0; k < j; ++k) {
                w -= flatA[ii * N + k] * flatA[k * N + j];
            }
            flatA[ii * N + j] = w / flatA[j * N + j];
        }

        // Solve for upper part (j >= i)
        for (int j = i; j < n; ++j) {
            double w = flatA[ii * N + j];
#pragma omp parallel for schedule(static)
            for (int k = 0; k < i; ++k) {
                w -= flatA[ii * N + k] * flatA[k * N + j];
            }
            flatA[ii * N + j] = w;
        }
    }

    /* --- Forward substitution: y = L^{-1} * b --------------------------- */
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        if (i > 0)
#pragma omp parallel for schedule(static)
            for (int j = 0; j < i; ++j)
                w -= flatA[static_cast<size_t>(i) * N + j] * y[j];
        y[i] = w;
    }

    /* --- Backward substitution: x = U^{-1} * y -------------------------- */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        if (i + 1 < n)
#pragma omp parallel for schedule(static)
            for (int j = i + 1; j < n; ++j)
                w -= flatA[static_cast<size_t>(i) * N + j] * x[j];
        x[i] = w / flatA[static_cast<size_t>(i) * N + i];
    }

    // Copy back to the original 2D vector
    for (size_t i = 0; i < N; ++i)
        std::copy(flatA.begin() + i * N, flatA.begin() + (i + 1) * N, A[i].begin());
}
