/* Optimised kernel for 3 matrix multiplications
 *
 *   E = A * B            (ni × nj)
 *   F = C * D            (nj × nl)
 *   G = E * F            (ni × nl)
 *
 * The function keeps the exact interface used by the harness.
 * Each outer loop is parallelised with OpenMP and the inner
 * computations are performed with pointer arithmetic to minimise
 * indirection.  The code is compiled with GCC -O2 -fopenmp.
 */
void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
                std::vector<std::vector<double>>& E,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& F,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D,
                std::vector<std::vector<double>>& G)
{
    /* ------------------------------------------------------------------ */
    /* Step 1 : E = A * B  (ni × nj)                                     */
    /* ------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i)
    {
        double* e_row = E[i].data();
        const double* a_row = A[i].data();
        for (int j = 0; j < nj; ++j)
        {
            double acc = 0.0;
            const double* a_ptr = a_row;
            const double* b_col = nullptr;
            for (int k = 0; k < nk; ++k)
            {
                b_col = &B[k][j];
                acc += (*a_ptr++) * (*b_col);
            }
            e_row[j] = acc;
        }
    }

    /* ------------------------------------------------------------------ */
    /* Step 2 : F = C * D  (nj × nl)                                     */
    /* ------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < nj; ++i)
    {
        double* f_row = F[i].data();
        const double* c_row = C[i].data();
        for (int j = 0; j < nl; ++j)
        {
            double acc = 0.0;
            const double* c_ptr = c_row;
            const double* d_col = nullptr;
            for (int k = 0; k < nm; ++k)
            {
                d_col = &D[k][j];
                acc += (*c_ptr++) * (*d_col);
            }
            f_row[j] = acc;
        }
    }

    /* ------------------------------------------------------------------ */
    /* Step 3 : G = E * F  (ni × nl)                                     */
    /* ------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i)
    {
        double* g_row = G[i].data();
        const double* e_row = E[i].data();
        for (int j = 0; j < nl; ++j)
        {
            double acc = 0.0;
            const double* e_ptr = e_row;
            const double* f_col = nullptr;
            for (int k = 0; k < nj; ++k)
            {
                f_col = &F[k][j];
                acc += (*e_ptr++) * (*f_col);
            }
            g_row[j] = acc;
        }
    }
}
