#include <vector>
#include <cstddef>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A)
{
    const std::size_t stride = static_cast<std::size_t>(n);
    const std::size_t inner = static_cast<std::size_t>(n - 2);
    const double div9 = 1.0 / 9.0;

    // Interpreting the 2‑D vector as a flat array for faster indexing.
    double* const base = &A[0][0];

    for (int t = 0; t < tsteps; ++t)
    {
        for (std::size_t i = 1; i <= inner; ++i)
        {
            const std::size_t i_offset = i * stride;
            for (std::size_t j = 1; j <= inner; ++j)
            {
                // Manual indexing – avoids the vector::operator[] overhead.
                std::size_t idx      = i_offset + j;
                std::size_t idx_up   = idx - stride - 1;
                std::size_t idx_kur  = idx - stride;
                std::size_t idx_down = idx + stride - 1;

                base[idx] = ( base[idx_up]     + base[idx_kur]     + base[idx + 1]
                           +   base[idx - 1] + base[idx]          + base[idx + 1]
                           +   base[idx_down] + base[idx_down + 1]+ base[idx_down + 2] ) * div9;
            }
        }
    }
}
```

This implementation:

1. **Flat indexing** eliminates repeated bounds checks from `operator[]` on `std::vector<std::vector<double>>`.
2. **Pointer arithmetic** keeps the compiler’s optimizer happy, leading to better inlining and SIMD opportunities.
3. **Simple loop bounds** (`< tsteps` instead of `<= tsteps-1`) make the code clearer.
4. The behaviour (in‑place updates, identical numerics) remains unchanged.

