// Flatten the 2D data into a 1D array for better cache locality.
// The data is stored column‑major: data[i*m + j] == data[i][j].
using Matrix = std::vector<double>;

static inline double* element(Matrix& mat, int i, int j, int m) {
    return &mat[i * m + j];
}

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    constexpr double eps = 0.1;
    const int N = n, M = m;              // for lambda capture
    const double invSqrtN = 1.0 / std::sqrt(double(n));

    // ---- 1. Flatten the input data -------------------------------------------------
    Matrix flatData(N * M);
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < N; ++i)
        for (int j = 0; j < M; ++j)
            flatData[i * M + j] = data[i][j];

    // ---- 2. Mean -------------------------------------------------------------
#pragma omp parallel for schedule(static)
    for (int j = 0; j < M; ++j) {
        double sum = 0.0;
        for (int i = 0; i < N; ++i)
            sum += flatData[i * M + j];
        mean[j] = sum / N;
    }

    // ---- 3. Standard deviation ----------------------------------------------------
#pragma omp parallel for schedule(static)
    for (int j = 0; j < M; ++j) {
        double sum = 0.0;
        for (int i = 0; i < N; ++i) {
            double d = flatData[i * M + j] - mean[j];
            sum += d * d;
        }
        double s = std::sqrt(sum / N);
        stddev[j] = (s <= eps) ? 1.0 : s;
    }

    // ---- 4. Normalize columns ----------------------------------------------------
#pragma omp parallel for schedule(static)
    for (int i = 0; i < N; ++i) {
        double* row = &flatData[i * M];
        for (int j = 0; j < M; ++j) {
            row[j] = (row[j] - mean[j]) * invSqrtN / stddev[j];
        }
    }

    // ---- 5. Correlation matrix ----------------------------------------------------
    // Allocate a linear buffer for corr in column‑major order for speed,
    // then copy back to the 2‑D vector.
    Matrix flatCorr(M * M, 0.0);

#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < M; ++i) {
        for (int j = i; j < M; ++j) {
            if (i == j) {
                flatCorr[i * M + j] = 1.0;
                continue;
            }
            double sum = 0.0;
            for (int k = 0; k < N; ++k)
                sum += flatData[k * M + i] * flatData[k * M + j];
            flatCorr[i * M + j] = sum;
            flatCorr[j * M + i] = sum;   // symmetry
        }
    }

    // Copy back to the vector<vector<double>> representation expected by harness
    for (int i = 0; i < M; ++i)
        for (int j = 0; j < M; ++j)
            corr[i][j] = flatCorr[i * M + j];
}
