#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    // Prefetch stride for row-major arrays
    const double alpha_local = alpha;
    const double beta_local  = beta;

    // Parallel over the outermost dimension (increasing i guarantees
    // no race on C[i][*] and the updates to C[k][*] are safe because
    // k < i and each i is processed once in order).
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        const double* A_row_i = A[i].data();      // A[i][*]
        const double* B_row_i = B[i].data();      // B[i][*]
        double* C_row_i = C[i].data();            // C[i][*]
        const double A_ii = A_row_i[i];           // A[i][i]

        // For each column j in C and B
        for (int j = 0; j < n; ++j) {
            const double B_ij = B_row_i[j];
            double temp2 = 0.0;

            // Accumulate the inner product over k < i
            for (int k = 0; k < i; ++k) {
                const double A_ik = A_row_i[k];   // A[i][k]
                double* C_row_k = C[k].data();    // C[k][*]
                const double B_kj = B[k][j];      // B[k][j]

                // Update the lower triangular part of C
                C_row_k[j] += alpha_local * B_ij * A_ik;

                // Compute contribution to the upper part
                temp2 += B_kj * A_ik;
            }

            // Update the diagonal/upper part of C
            C_row_i[j] = beta_local * C_row_i[j]
                       + alpha_local * B_ij * A_ii
                       + alpha_local * temp2;
        }
    }
}
