#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>> &A,
                 std::vector<double>                 &s,
                 std::vector<double>                 &q,
                 std::vector<double>                 &p,
                 std::vector<double>                 &r)
{
    /* 
     * We keep the exact semantics of the original code:
     *   s[j] = Σ_i r[i] * A[i][j]
     *   q[i] = Σ_j (A[i][j] + p[j])
     */

    /* compute q[i] in parallel, each thread works on a contiguous block of rows */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double local_sum = 0.0;
        const std::vector<double> &Ai = A[i];
        for (int j = 0; j < m; ++j) {
            local_sum += Ai[j] + p[j];
        }
        q[i] = local_sum;
    }

    /* reset s[j] to zero before accumulation */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) s[j] = 0.0;

    /* accumulate s[j] in parallel.  Each thread keeps a local buffer
     * to avoid atomic operations, then we reduce the buffers into s.
     */
    const int num_threads = omp_get_max_threads();
    std::vector<std::vector<double>> s_private(num_threads,
                                               std::vector<double>(m, 0.0));

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::vector<double> &s_local = s_private[tid];

        #pragma omp for schedule(static)
        for (int i = 0; i < n; ++i) {
            const std::vector<double> &Ai = A[i];
            double r_i = r[i];
            for (int j = 0; j < m; ++j) {
                s_local[j] += r_i * Ai[j];
            }
        }
    }

    /* Reduce local s into the final vector */
    for (int tid = 0; tid < num_threads; ++tid) {
        const std::vector<double> &s_local = s_private[tid];
        for (int j = 0; j < m; ++j) {
            s[j] += s_local[j];
        }
    }
}
