            for (int j = 0; j < ny; ++j) {
                ey[0][j] = _fict_[t];
            }

            // 2) UpdateEy(nx, ny, ey, hz)
            // Parallel over i and j – independent operations
            #pragma omp for collapse(2) schedule(static)
            for (int i = 1; i < nx; ++i) {
                for (int j = 0; j < ny; ++j) {
                    ey[i][j] -= 0.5 * (hz[i][j] - hz[i - 1][j]);
                }
            }

            // 3) UpdateEx(nx, ny, ex, hz)
            #pragma omp for collapse(2) schedule(static)
            for (int i = 0; i < nx; ++i) {
                for (int j = 1; j < ny; ++j) {
                    ex[i][j] -= 0.5 * (hz[i][j] - hz[i][j - 1]);
                }
            }

            // 4) UpdateHz(nx, ny, ex, ey, hz)
            #pragma omp for collapse(2) schedule(static)
            for (int i = 0; i < nx - 1; ++i) {
                for (int j = 0; j < ny - 1; ++j) {
                    hz[i][j] -= 0.7 * (ex[i][j + 1] - ex[i][j] + ey[i + 1][j] - ey[i][j]);
                }
            }
        }
    }
}
