#include <vector>
#include <cstddef>
#include <omp.h>

/* Optimised version of the kernel.  The external interface is unchanged
 * so that the harness continues to call it without modification.  The
 * implementation relies on :
 *   • Contiguous 1‑D memory for the 2‑D arrays (row major).
 *   • Pre‑allocated temporary arrays for the row‐wise tridiagonal
 *     solves to avoid re‑allocating inside the time loop.
 *   • OpenMP parallelisation of the outer “i” loops.
 *   • Local inlining of all frequently used coefficients.
 */
inline const double* to_1d(const std::vector<std::vector<double>>& v) {
    return v.size() == 0 ? nullptr : &v[0][0];
}

void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q) {
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0, B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a = -mul1 / 2.0,    b = 1.0 + mul1,    c = a;
    const double d = -mul2 / 2.0,    e = 1.0 + mul2,    f = d;

    const std::size_t N = static_cast<std::size_t>(n);
    const std::size_t NV = N * N;                  // total elements
    double* u_dat = const_cast<double*>(to_1d(u));
    double* v_dat = const_cast<double*>(to_1d(v));
    double* p_dat = const_cast<double*>(to_1d(p));
    double* q_dat = const_cast<double*>(to_1d(q));

    // temporary row buffers for *p* and *q*
    std::vector<double> p_row(n), q_row(n);

    for (int t = 1; t <= tsteps; ++t) {
        /* ---------- First half: solve for v ----------
         *   Loops over columns i (1 .. n-2)
         */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            const std::size_t i_off = static_cast<std::size_t>(i) * N;

            // initialise boundary values
            v_dat[0 * N + i] = 1.0;
            p_dat[i_off + 0] = 0.0;
            q_dat[i_off + 0] = v_dat[0 * N + i];

            /* tridiagonal forward sweep over j */
            for (int j = 1; j < n - 1; ++j) {
                const std::size_t idx = static_cast<std::size_t>(j) * N + i;
                double denom = a * p_dat[i_off + j - 1] + b;
                p_dat[i_off + j] = -c / denom;
                double val = (-d * u_dat[j * N + i - 1]
                              + (1.0 + 2.0 * d) * u_dat[idx]
                              - f * u_dat[j * N + i + 1]
                              - a * q_dat[i_off + j - 1]) / denom;
                q_dat[i_off + j] = val;
            }

            v_dat[(n - 1) * N + i] = 1.0;

            /* backward sweep to fill v */
            for (int j = n - 2; j >= 1; --j) {
                const std::size_t idx = static_cast<std::size_t>(j) * N + i;
                v_dat[idx] = p_dat[i_off + j] * v_dat[(j + 1) * N + i]
                           + q_dat[i_off + j];
            }
        }

        /* ---------- Second half: solve for u ----------
         *   Loops over rows i (1 .. n-2)
         */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            const std::size_t i_off = static_cast<std::size_t>(i) * N;

            // initialise boundary values
            u_dat[i * N + 0] = 1.0;
            p_dat[i_off + 0] = 0.0;
            q_dat[i_off + 0] = u_dat[i * N + 0];

            /* tridiagonal forward sweep over j */
            for (int j = 1; j < n - 1; ++j) {
                const std::size_t idx = static_cast<std::size_t>(j) * N + i;
                double denom = d * p_dat[i_off + j - 1] + e;
                p_dat[i_off + j] = -f / denom;
                double val = (-a * v_dat[(i - 1) * N + j]
                              + (1.0 + 2.0 * a) * v_dat[idx]
                              - c * v_dat[(i + 1) * N + j]
                              - d * q_dat[i_off + j - 1]) / denom;
                q_dat[i_off + j] = val;
            }

            u_dat[i * N + (n - 1)] = 1.0;

            /* backward sweep to fill u */
            for (int j = n - 2; j >= 1; --j) {
                const std::size_t idx = static_cast<std::size_t>(j) * N + i;
                u_dat[idx] = p_dat[i_off + j] * u_dat[i * N + (j + 1)]
                           + q_dat[i_off + j];
            }
        }
    }
}
