#include <cmath>
#include <vector>
#include <omp.h>

/*
 * Optimised kernel_deriche – same behavior, but
 *   * Avoids many temporary vectors
 *   * Uses flat arrays for cache friendliness
 *   * Parallelises all loops with OpenMP
 *
 * The harness still passes `std::vector<std::vector<float>>`
 * so the wrapper converts to flat storage before/after.
 */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* ---------- flat representation ---------- */
    const int N = w * h;
    std::vector<float> in(N), out(N), tmp1(N), tmp2(N);
    auto idx = [h](int i, int j){ return i * h + j; };

    /* copy input into a flat array */
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            in[idx(i,j)] = imgIn[i][j];

    /* ---------- coefficient pre‑calculation ---------- */
    const float k  = 1.0f - std::exp(-alpha) * (1.0f - std::exp(-alpha)) /
                     (1.0f + 2.0f * static_cast<float>(alpha) * std::exp(-alpha) -
                      std::exp(2.0f * static_cast<float>(alpha)));

    const float exp_neg_a   = std::exp(-alpha);
    const float exp_neg_2a  = std::exp(-2.0f * static_cast<float>(alpha));

    const float a1 = a5 = k;
    const float a2 = a6 = k * exp_neg_a * (static_cast<float>(alpha) - 1.0f);
    const float a3 = a7 = k * exp_neg_a * (static_cast<float>(alpha) + 1.0f);
    const float a4 = a8 = -k * exp_neg_2a;
    const float b1 = std::pow(2.0f, -static_cast<float>(alpha));
    const float b2 = -exp_neg_2a;
    const float c1 = 1.0f, c2 = 1.0f;

    /* ---------- row forward filtering (y1) ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            const float x = in[idx(i,j)];
            tmp1[idx(i,j)] = a1 * x + a2 * xm1 + b1 * ym1 + b2 * ym2;
            xm1 = x;  ym2 = ym1;  ym1 = tmp1[idx(i,j)];
        }
    }

    /* ---------- row backward filtering (y2) ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h-1; j >= 0; --j) {
            const float x = in[idx(i,j)];
            tmp2[idx(i,j)] = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            xp2 = xp1;  xp1 = x;  yp2 = yp1;  yp1 = tmp2[idx(i,j)];
        }
    }

    /* ---------- combine forward/backward ---------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            out[idx(i,j)] = c1 * (tmp1[idx(i,j)] + tmp2[idx(i,j)]);

    /* ---------- column forward filtering (tmp1) ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float y = out[idx(i,j)];
            tmp1[idx(i,j)] = a5 * y + a6 * tm1 + b1 * ym1 + b2 * ym2;
            tm1 = y;    ym2 = ym1;    ym1 = tmp1[idx(i,j)];
        }
    }

    /* ---------- column backward filtering (tmp2) ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w-1; i >= 0; --i) {
            const float y = out[idx(i,j)];
            tmp2[idx(i,j)] = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            tp2 = tp1;    tp1 = y;    yp2 = yp1;    yp1 = tmp2[idx(i,j)];
        }
    }

    /* ---------- final combination into output ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            out[idx(i,j)] = c2 * (tmp1[idx(i,j)] + tmp2[idx(i,j)]);

    /* ---------- copy back to 2‑D vectors ---------- */
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = out[idx(i,j)];
}
